// Claude API Response auslesen (von VOR dem Postgres-Node holen)
const response = $('Claude API Analyse').first().json;
let analysisText = '';

if (response.content && response.content.length > 0) {
  analysisText = response.content[0].text;
} else if (response.error) {
  analysisText = ':rotating_light: *Claude API Fehler:* ' + JSON.stringify(response.error);
} else {
  analysisText = ':warning: Unerwartete API-Antwort: ' + JSON.stringify(response).substring(0, 500);
}

// Slack-Nachricht formatieren
const slackMessage = ':bar_chart: *TT2GO Google Ads — KI-Wochenbericht*\n' +
  '_Analyse erstellt von Claude AI am ' + new Date().toLocaleDateString('de-DE') + '_\n\n' +
  analysisText;

return [{ json: { text: slackMessage } }];
